  ('social-worker-moex-06130', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不是社會工作人員在災難發生時適合做的事？', '["評估案主受災狀況", "發放救濟物資與救濟金", "安置災民", "讓不願離開災區的人簽切結書"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
