  ('social-worker-moex-06132', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '任務性團體在處理團體衝突時，不建議進行下列何者？', '["運用面質的技術，協助成員解決衝突狀態", "將衝突視為團體發展中很自然，且很有幫助的部分", "蒐集事實資料，針對有衝突的部分請專家判斷", "強調團體討論中已經達成一致性的部分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06133', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '文化因素對於團體凝聚力的影響，不包括下列何者？', '["來自不同背景成員的動機和期待", "成員表達不同層次的感受，就像文化規範的影響", "文化特性影響不同的團體目標", "在多元文化團體中的次團體類型"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06134', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不是虛擬團體（virtual groups）的優點？', '["缺乏交通工具或是住得太遠的人，適合參加虛擬團體", "虛擬團體有利於罹患嚴重疾病或身體異常虛弱的人參加", "虛擬團體中所提供的資訊及服務的品質，是容易掌握的", "有些團體的討論容易使人被污名化時，則適合用虛擬團體"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06135', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列有關治療性團體與任務性團體的比較，何者錯誤？', '["治療性團體的溝通是開放的、任務性團體的成員較傾向與領導者溝通", "治療性團體是以滿足成員需求為目的、任務性團體是以達成任務為目的", "治療性團體與任務性團體的成員，都會被期待揭露自己的問題與關心的事情", "治療性團體與任務性團體在運作時，都期待成員的高度參與"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06136', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列有關身心障礙者團體的敘述，何者錯誤？', '["領導者應把握團體目標，主導活動討論的內容", "領導者需對成員障礙類別有一定的認知，以貼近成員，加強對團體的認同", "領導者應協助參與團體的身心障礙者，獲得瞭解團體訊息的資源，例如：為團體中的聽覺障礙者安排 手語翻譯員", "領導者應依照身心障礙者的特質，安排合適的物理環境，例如：為脊髓損傷者辦理的團體場地，應有 足夠輪椅迴轉的空間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06137', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '帶領兒童團體時，領導者應注意的事項，下列何者錯誤？', '["兒童在團體活動中難長時間集中注意力，應適度安排休息時間", "兒童團體針對兒童發展階段而有不同的考量。學齡期正值口語表達初期，可多設計口語表達活動來作 為訓練", "領導者應使用與兒童貼近的語言，以增加親近感", "兒童團體的活動單張，可用孩子喜歡的卡通人物作為設計圖案，以增加兒童參與團體的意願"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06138', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列有關「團體結束階段」的敘述，何者錯誤？', '["若社會工作人員在團體執行過程中，必須離職且成員不同意更換領導者，則需要提前結束團體", "若成員在團體結束階段，出現分離焦慮，領導者應接納並與成員討論", "在進行團體評鑑時，應有多元的策略，可以同時從團體、成員及領導者等不同面向，進行評鑑", "若成員因為跟不上團體進度而退出團體，則與社會工作人員帶領團體的方式無關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06139', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體工作紀錄可作為工作者檢視及評鑑團體運作的重要方式之一，下列有關團體紀錄的敘述何者錯誤？', '["「摘要式紀錄」較能具體且深入的呈現團體過程與內容，適用於量化的評鑑，所花費的時間較多", "團體紀錄可以檢視團體目標達成狀態及成員參與狀態等重要面向，是團體成效評鑑工具之一", "紀錄裡的文字內容、相片等，須遵守保密原則及匿名處理", "任務性團體的紀錄，需在下次聚會前發給成員檢閱，並於下次會議開始前進行修正"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
